  "questionProse": [
    "איזו מבנה נתונים משמש בדרך כלל ליישום חיפוש ברוחב (BFS)?"
  ],
  "questionCode": [],
  "hintsProse": [
    "הסתכל על תבנית הגישה, לא על שם המבנה. התשובה הנכונה נובעת בדרך כלל ממה שצריך לקרות ראשון או אחרון."
  ],
